<template>
  <div ref="charts" style="height:100%;width:100%"></div>
</template>

<script setup>
import * as echarts from "echarts";
import { onMounted, ref, watch } from "vue-demi";
const charts = ref(null);
const test = [1,1,1,1];
const props = defineProps({
  count: Number,
  max: Number,
  status: Object,
  statustime: Object,
  statustimeinterval: Object,
  name: String,
});
let chartDom;
let option = {
  color: ["#4FD000", "#4FD000", "#4FD000", "#4FD000"],
  grid: {
    left: "2%",
    top: "20%",
    width: "95%",
    height: "65%",
  },
  visualMap: {
    show: false,
    pieces: [
      {
        gt: 0,
        lte: props.max * 0.5,
        color: "#b7ef0c",
      },
      {
        gt: props.max * 0.5,
        lte: props.max * 0.8,
        color: "#21d116",
      },
      {
        gt: props.max * 0.8,
        color: "#eb0000",
      },
    ],
    outOfRange: {
      color: "#999",
    },
  },
  xAxis: {
    type: "category",
    min: 0,
    data: Array.from({ length: props.count }).map((v, k) => k + 1 + "架"),
  },
  legend: {
    top: 18,
    textStyle: {
      fontSize: 15,
    },
    data: [],
  },
  tooltip: {
    trigger: "axis",
    axisPointer: {
      type: "shadow",
    },
    
    formatter: (params) =>  {
      let returnData = "";
      let indexColor = params[0].color;
      returnData+=(params[0].dataIndex+1)+"架</br>"
      returnData+= '<span style="display:inline-block;margin-right:5px;border-radius:10px;width:9px;height:9px;background:'+ indexColor +'"></span>'
      returnData +=params[0].seriesName+" "+params[0].data + "Bar</br>"
      returnData +='<span style="display:inline-block;margin-right:5px;border-radius:10px;width:9px;height:9px;background:#4FD000"></span>'
      returnData +="上传压力时间: "+props.statustime[params[0].dataIndex]+"</br>"
      if (props.statustimeinterval[params[0].dataIndex]>0 && props.statustimeinterval[params[0].dataIndex]<180){
        returnData+='<span style="display:inline-block;margin-right:5px;border-radius:10px;width:9px;height:9px;background:#4FD000"></span>'
      }else{
        returnData+='<span style="display:inline-block;margin-right:5px;border-radius:10px;width:9px;height:9px;background:#a90000"></span>'
      }
      returnData+="上传压力间隔: "+props.statustimeinterval[params[0].dataIndex]
      return returnData
    },
  },
  yAxis: {
    type: "value",
    min: 0,
    max: props.max,
    nameGap: 5,
    interval: 252,
    name: props.name,
  },
  // yAxis: {
  //   type: "value",
  //   show: false,
  // },
  series: [{ name:props.name, data:[] , type: "bar"}],
};
const reDraw = () => {
  option.series[0].data = [1, 1, 1, 1, 1, 1];
  chartDom.setOption(option)
  chartDom.resize();
};
watch(
  () => props.count,
  (val) => {
    option.xAxis ={
    type: "category",
    min: 0,
    data: Array.from({ length: val }).map((v, k) => k + 1 + "架"),
  }
  chartDom.setOption(option);
  chartDom.resize();
  })

watch(
  () => props.status,
  (val) => {
    //console.log("aa",props.status)
    option.series[0].data = props.status;
   // option.series[0].data1 = props.statustimeinterval;
    chartDom.setOption(option);
    chartDom.resize();
  },
  {
    deep: true,
  }
);



onMounted(() => {

  chartDom = echarts.init(charts.value);
  reDraw();
});
</script>

